pragma solidity >=0.4.22 <0.9.0;
pragma experimental ABIEncoderV2;

contract MedNftCreation {

    event NewMedNFT(uint id, string medNftId, uint32[] prompt);

    uint cooldownTime = 1 days;

    struct MedNft {
        string MedNftId;
        uint32[] prompt;
        uint32 level;
        uint32 readyTime;
        uint16 winCount;
        uint16 lossCount;
    }

    MedNft[] public medNfts;

    mapping (uint => address) public medNftToOwner;
    mapping (address => uint) ownerMedNftCount;

    function createMedNft(string memory _id, uint32[] memory _prompt) public {
        require(ownerMedNftCount[msg.sender] == 0);
        medNfts.push(MedNft(_id, _prompt, 1,uint32(block.timestamp + cooldownTime), 0, 0));
        uint id = medNfts.length - 1;
        medNftToOwner[id] = msg.sender;
        ownerMedNftCount[msg.sender]++; 
        emit NewMedNFT(id, _id, _prompt);
    }

    function getMedNft(address _address) public view returns (string[] memory, uint32[][] memory, uint32[] memory, uint32[] memory, uint16[] memory, uint16[] memory){
        uint256 ownerCount = ownerMedNftCount[_address];
        string[] memory medNftIds = new string[](ownerCount);
        uint32[][] memory prompts = new uint32[][](ownerCount);
        uint32[] memory levels = new uint32[](ownerCount);
        uint32[] memory readyTimes = new uint32[](ownerCount);
        uint16[] memory winCounts = new uint16[](ownerCount);
        uint16[] memory lossCounts = new uint16[](ownerCount);

        uint256 counter = 0;
        for (uint256 i = 0; i < medNfts.length; i++) {
            if (medNftToOwner[i] == _address) {
                medNftIds[counter] = medNfts[i].MedNftId;
                prompts[counter] = medNfts[i].prompt;
                levels[counter] = medNfts[i].level;
                readyTimes[counter] = medNfts[i].readyTime;
                winCounts[counter] = medNfts[i].winCount;
                lossCounts[counter] = medNfts[i].lossCount;
                counter++;
            }
        }

    return (medNftIds, prompts, levels, readyTimes, winCounts, lossCounts);
    }
}
